final:
module RefModule(
    input       clk   ,
    input       reset ,

    output reg  [3:0] out
);

    // 4-bit Ring Counter
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset)
            out <= 4'b0001;
        else
            out <= {out[2:0], out[3]};
    end

endmodule
